function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Case 0: No swap
    // Find the longest balanced substring in the original string s
    for (let len = 2; len <= n; len += 2) {
        for (let i = 0; i <= n - len; i++) {
            const sub = s.substring(i, i + len);
            let count0 = 0;
            let count1 = 0;
            for (let char of sub) {
                if (char === '0') count0++;
                else count1++;
            }
            if (count0 === count1) {
                maxLen = Math.max(maxLen, len);
            }
        }
    }

    // Case 1: One swap
    // Iterate over all possible pairs of indices (i, j) to swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Create the new string s_swapped by swapping s[i] and s[j]
            let s_swapped_array = s.split('');
            [s_swapped_array[i], s_swapped_array[j]] = [s_swapped_array[j], s_swapped_array[i]];
            const s_swapped = s_swapped_array.join('');

            // Find the longest balanced substring in s_swapped
            for (let len = 2; len <= n; len += 2) {
                for (let k = 0; k <= n - len; k++) {
                    const sub = s_swapped.substring(k, k + len);
