                    let count1 = 0;
                    for (let char of sub) {
                        if (char === '0') count0++;
                        else count1++;
                    }
                    if (count0 === count1) {
                        maxLen = Math.max(maxLen, len);
                    }
                }
            }
        }
    }

    // The problem states that an empty substring is balanced (length 0),
    // so maxLen is at least 0.
    return maxLen;
}

