function solve(s: string): number {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced substring in a given string t
    const findLongestBalanced = (t: string): number => {
        const len = t.length;
        let currentMax = 0;

        // Optimized search for balanced substring: use prefix sums (balance = count0 - count1)
        // A substring t[i..j] is balanced if prefix_sum[j+1] - prefix_sum[i] = 0,
        // or prefix_sum[j+1] = prefix_sum[i].
        // We use a map to store the first index where a certain balance was encountered.
        const balanceMap = new Map<number, number>();
        balanceMap.set(0, -1); // Balance 0 is seen before index 0 (at index -1)
        let currentBalance = 0;

        for (let j = 0; j < len; j++) {
            const char = t[j];
            currentBalance += (char === '0' ? 1 : -1); // Let's use 0 -> +1, 1 -> -1 for simplicity in balance tracking

            // Re-evaluating the balance definition for 0/1 count equality:
            // Balance = Count('0') - Count('1'). Substring is balanced if Balance = 0.
            // Let's stick to the original definition: count0 == count1.
            // If we map '0' -> +1 and '1' -> -1, a balanced substring has a net balance of 0.
            // Let's re-implement balance tracking based on this standard technique.

        }

        // Since the simple brute force in the reference solution is O(N^4) and too slow,
        // we must use the prefix sum method (O(N^2) for all substrings, or O(N) if we check the whole string, but here we check all).
        // For a fixed string t, the longest balanced substring can be found in O(N).

        let count0 = 0;
        let count1 = 0;
        const balanceMapOptimized = new Map<number, number>();
        balanceMapOptimized.set(0, -1);
        let balance = 0;
        let localMax = 0;

        for (let j = 0; j < len; j++) {
            if (t[j] === '0') {
                count0++;
                balance++;
            } else {
                count1++;
                balance--;
            }

            if (balanceMapOptimized.has(balance)) {
                const i = balanceMapOptimized.get(balance)! + 1;
                const currentLen = j - balanceMapOptimized.get(balance)!;
                localMax = Math.max(localMax, currentLen);
            } else {
                balanceMapOptimized.set(balance, j);
            }
        }
        return localMax;
    };


    // 1. Case 0: No swap
    maxLen = Math.max(maxLen, findLongestBalanced(s));

    // 2. Case 1: One swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Create the new string s_swapped by swapping s[i] and s[j]
            let s_swapped_array = s.split('');
            [s_swapped_array[i], s_swapped_array[j]] = [s_swapped_array[j], s_swapped_array[i]];
            const s_swapped = s_swapped_array.join('');

            // Find the longest balanced substring in s_swapped
            const currentMax = findLongestBalanced(s_swapped);
            maxLen = Math.max(maxLen, currentMax);
        }
    }

    // Note: The empty string is balanced with length 0, which is the initial value of maxLen.
    return maxLen;
}
