        // A balanced substring s[i..j] has sum(s[i..j]) = 0.
        // Let P[k] be the prefix sum up to index k-1 (P[0]=0).
        // Sum(s[i..j]) = P[j+1] - P[i]. We want P[j+1] = P[i].

        const balanceMap = new Map<number, number>();
        balanceMap.set(0, -1); // Map: balance_value -> first_occurrence_index
