/**
 * Finds the maximum length of a balanced substring after at most one swap.
 * A balanced string has an equal number of '0's and '1's.
 * 
 * @param s The binary string.
 * @returns The maximum length of a balanced substring.
 */
function solve(s: string): number {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced substring in a given string t
    const findLongestBalanced = (t: string): number => {
        let currentMax = 0;
        const lenT = t.length;

        // Use a balance counter: +1 for '1', -1 for '0' (or vice versa)
        // A substring s[i..j] is balanced if count('0') == count('1').
        // If we map '1' -> 1 and '0' -> -1, then a balanced substring has a prefix sum change of 0.
        // Let's map '1' -> 1 and '0' -> -1.

        // Prefix sum approach: sum[j] - sum[i-1] = 0 => sum[j] = sum[i-1]
        const prefixSum = new Array(lenT + 1).fill(0);
        for (let i = 0; i < lenT; i++) {
            const val = t[i] === '1' ? 1 : -1;
            prefixSum[i + 1] = prefixSum[i] + val;
        }

        // Map to store the first index where a specific prefix sum is encountered
        const sumMap = new Map<number, number>();
        sumMap.set(0, 0); // Sum 0 occurs before the string starts (index 0)

        for (let j = 1; j <= lenT; j++) {
            const currentSum = prefixSum[j];
            if (sumMap.has(currentSum)) {
                const i = sumMap.get(currentSum)!;
                // The substring t[i...j-1] has a balance of 0, length is j - i
                currentMax = Math.max(currentMax, j - i);
            } else {
                sumMap.set(currentSum, j);
            }
        }
        return currentMax;
    };

    // Case 0: No swap
    maxLen = Math.max(maxLen, findLongestBalanced(s));

    // Case 1: One swap
    // Iterate over all possible pairs of indices (i, j) to swap
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Optimization: Only swap if the characters are different, otherwise it's redundant with Case 0
            if (s[i] === s[j]) continue;

            // Create the new string s_swapped by swapping s[i] and s[j]
            let s_swapped_array = s.split('');
            [s_swapped_array[i], s_swapped_array[j]] = [s_swapped_array[j], s_swapped_array[i]];
            const s_swapped = s_swapped_array.join('');

            // Find the longest balanced substring in s_swapped
            maxLen = Math.max(maxLen, findLongestBalanced(s_swapped));
        }
    }

    // The empty substring (length 0) is always balanced, so maxLen is at least 0.
    return maxLen;
}
